449→    eprintln!("release_brand: branding staging...");
450→    eprintln!("  staging: {}", args.staging.display());
451→    eprintln!("  registry: {}", args.registry.display());
452→    eprintln!("  commit: {}", args.commit);
453→
454→    // Parse comma-separated kit list
455→    let managed_kits: Vec<String> = args.managed_kits
456→        .split(',')
457→        .map(|s| s.trim().to_string())
458→        .filter(|s| !s.is_empty())
459→        .collect();
460→
461→    match vof::vofr_brand(&args.staging, &args.registry, &args.commit, &managed_kits) {
462→        Ok(result) => {
