/// Arguments for release_brand command
#[derive(clap::Args, Debug)]
struct ReleaseBrandArgs {
    /// Staging directory with collected assets
    #[arg(long)]
    staging: PathBuf,

    /// Path to vovr_registry.json
    #[arg(long)]
    registry: PathBuf,

