 51→// ============================================================================
 52→// stdout capture
 53→// ============================================================================
 54→
 55→/// Capture stdout from a synchronous handler, returning output as MCP tool result.
 56→/// Uses fd-level redirection with a reader thread to avoid pipe deadlock.
 57→fn jjrm_capture<F: FnOnce() -> i32>(f: F) -> Result<CallToolResult, McpError> {
 58→    use std::io::{Read, Write};
 59→    use std::os::unix::io::FromRawFd;
 60→
 61→    unsafe {
 62→        let mut fds = [0i32; 2];
 63→        if libc::pipe(fds.as_mut_ptr()) != 0 {
 64→            return Err(McpError::internal_error("pipe creation failed", None));
 65→        }
 66→        let (read_fd, write_fd) = (fds[0], fds[1]);
 67→
 68→        let saved = libc::dup(libc::STDOUT_FILENO);
 69→        if saved < 0 {
 70→            libc::close(read_fd);
 71→            libc::close(write_fd);
 72→            return Err(McpError::internal_error("dup stdout failed", None));
 73→        }
 74→        libc::dup2(write_fd, libc::STDOUT_FILENO);
 75→        libc::close(write_fd);
 76→
 77→        // Reader thread prevents pipe buffer deadlock
 78→        let reader_handle = std::thread::spawn(move || {
 79→            let mut reader = std::fs::File::from_raw_fd(read_fd);
 80→            let mut output = String::new();
 81→            reader.read_to_string(&mut output).ok();
 82→            output
 83→        });
 84→
 85→        let code = f();
 86→        std::io::stdout().flush().ok();
 87→
 88→        libc::dup2(saved, libc::STDOUT_FILENO);
 89→        libc::close(saved);
 90→
 91→        let output = reader_handle.join().unwrap_or_default();
 92→
 93→        if code == 0 {
 94→            Ok(CallToolResult::success(vec![Content::text(output)]))
 95→        } else {
 96→            Ok(CallToolResult::error(vec![Content::text(output)]))
 97→        }
 98→    }
 99→}
100→
101→/// Async variant of jjrm_capture for handlers that need .await
102→async fn jjrm_capture_async<F, Fut>(f: F) -> Result<CallToolResult, McpError>
103→where
104→    F: FnOnce() -> Fut,
105→    Fut: std::future::Future<Output = i32>,
106→{
107→    use std::io::{Read, Write};
108→    use std::os::unix::io::FromRawFd;
109→
110→    unsafe {
111→        let mut fds = [0i32; 2];
112→        if libc::pipe(fds.as_mut_ptr()) != 0 {
113→            return Err(McpError::internal_error("pipe creation failed", None));
114→        }
115→        let (read_fd, write_fd) = (fds[0], fds[1]);
116→
117→        let saved = libc::dup(libc::STDOUT_FILENO);
118→        if saved < 0 {
119→            libc::close(read_fd);
120→            libc::close(write_fd);
121→            return Err(McpError::internal_error("dup stdout failed", None));
122→        }
123→        libc::dup2(write_fd, libc::STDOUT_FILENO);
124→        libc::close(write_fd);
125→
126→        let code = f().await;
127→        std::io::stdout().flush().ok();
128→
129→        libc::dup2(saved, libc::STDOUT_FILENO);
130→        libc::close(saved);
131→
132→        // Read captured output (pipe write end closed by dup2 restore)
133→        let mut reader = std::fs::File::from_raw_fd(read_fd);
134→        let mut output = String::new();
135→        reader.read_to_string(&mut output).ok();
136→
137→        if code == 0 {
138→            Ok(CallToolResult::success(vec![Content::text(output)]))
139→        } else {
140→            Ok(CallToolResult::error(vec![Content::text(output)]))
141→        }
142→    }
143→}
